import json
import yaml

class UserPreferences:
    def __init__(self, preferences):
        self.preferences = preferences

    def to_dict(self):
        return {
            'preferences': self.preferences
        }

    @staticmethod
    def from_dict(data):
        if 'preferences' in data and isinstance(data['preferences'], dict):
            return UserPreferences(data['preferences'])
        raise ValueError("Invalid data structure for UserPreferences")

def save_preferences_to_file(preferences, filename):
    with open(filename, 'w') as file:
        json.dump(preferences.to_dict(), file)

def load_preferences_from_file(filename):
    with open(filename, 'r') as file:
        data = json.load(file)
        return UserPreferences.from_dict(data)

